#include <iostream>
using namespace std;

class Number
{
public:
    int value;

    // Constructor to initialize value
    Number(int v)
    {
        value = v;
    }

    // Overload + operator
    Number operator+(Number obj)
    {
        Number temp(0);
        temp.value = value + obj.value;
        return temp;
    }
};

int main()
{
    int a, b;
    cin >> a >> b;

    Number n1(a), n2(b);

    Number result = n1 + n2;

    cout << result.value;

    return 0;
}
